mapper.select:
select id, coupon_name, coupon_type, threshold_amount, discount_amount, total_stock, surplus_stock, start_time,
end_time, valid_days, status, create_user, update_user, create_time, update_time, is_seckill
from coupon


        and coupon_name like concat('%',#{couponName},'%')


        and coupon_type = #{couponType}


        and threshold_amount = #{thresholdAmount}


        and discount_amount = #{discountAmount}


        and total_stock = #{totalStock}


        and surplus_stock = #{surplusStock}


        and status = #{status}


        and is_seckill = #{isSeckill}


order by create_time desc
